export const PropertyProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [properties, setProperties] = useState<Property[]>([]);
  const [leads, setLeads] = useState<Lead[]>([]);
  const [subscribers, setSubscribers] = useState<Subscriber[]>([]);
  const [posts, setPosts] = useState<BlogPost[]>([]);
  const [settings, setSettings] = useState<SiteSettings>(DEFAULT_SETTINGS);
  const [isLoading, setIsLoading] = useState(true);

  // Fetch Initial Data from Supabase
  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);
      try {
        const [propsRes, leadsRes, subsRes, postsRes, settingsRes] = await Promise.all([
          supabase.from('properties').select('*'),
          supabase.from('leads').select('*'),
          supabase.from('subscribers').select('*'),
          supabase.from('posts').select('*'),
          supabase.from('site_settings').select('*').single()
        ]);

        if (propsRes.data) setProperties(propsRes.data);
        if (leadsRes.data) setLeads(leadsRes.data);
        if (subsRes.data) setSubscribers(subsRes.data);
        if (postsRes.data) setPosts(postsRes.data);

        if (settingsRes.data) {
          // Merge with default to ensure new fields (like listingAgent) exist if not in DB yet
          setSettings({ ...DEFAULT_SETTINGS, ...settingsRes.data });
        } else {
            // Use defaults if table is empty
            setSettings(DEFAULT_SETTINGS); 
        }

      } catch (error) {
        console.error('Error fetching data from Supabase:', error);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []);

  // CRUD Operations - Properties

  const addProperty = async (property: Property) => {
    const { error } = await supabase.from('properties').insert([property]);
    if (error) throw error;
    setProperties(prev => [property, ...prev]);
  };

  const updateProperty = async (updatedProperty: Property) => {
    const { error } = await supabase
      .from('properties')
      .update(updatedProperty)
      .eq('id', updatedProperty.id);

    if (error) throw error;
    setProperties(prev => prev.map(p => p.id === updatedProperty.id ? updatedProperty : p));
  };

  const deleteProperty = async (id: string) => {
    const { error } = await supabase.from('properties').delete().eq('id', id);
    if (error) throw error;
    setProperties(prev => prev.filter(p => p.id !== id));
  };

  const getProperty = (id: string) => {
    return properties.find(p => p.id === id);
  };

  // CRUD Operations - Leads

  const addLead = async (lead: Lead) => {
    const { error } = await supabase.from('leads').insert([lead]);
    if (error) throw error;
    setLeads(prev => [lead, ...prev]);
  };

  const updateLeadStatus = async (id: string, status: Lead['status']) => {
    const { error } = await supabase.from('leads').update({ status }).eq('id', id);
    if (error) throw error;
    setLeads(prev => prev.map(l => l.id === id ? { ...l, status } : l));
  };

  // CRUD Operations - Subscribers

  const addSubscriber = async (email: string) => {
    if (subscribers.some(s => s.email === email)) return;

    const newSubscriber: Subscriber = {
      id: Date.now().toString(),
      email,
      date: new Date().toISOString()
    };

    // 1. Add to Supabase
    const { error } = await supabase.from('subscribers').insert([newSubscriber]);
    if (error) throw error;
    setSubscribers(prev => [newSubscriber, ...prev]);

    // 2. Sync with MailerLite
    try {
      await fetch('https://connect.mailerlite.com/api/subscribers', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${MAILERLITE_API_KEY}`,
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          email: email,
        })
      });
    } catch (err) {
      console.warn("MailerLite sync issue:", err);
    }
  };

  // CRUD Operations - Blog Posts

  const addPost = async (post: BlogPost) => {
    const { error } = await supabase.from('posts').insert([post]);
    if (error) throw error;
    setPosts(prev => [post, ...prev]);
  };

  const updatePost = async (updatedPost: BlogPost) => {
    const { error } = await supabase
      .from('posts')
      .update(updatedPost)
      .eq('id', updatedPost.id);

    if (error) throw error;
    setPosts(prev => prev.map(p => p.id === updatedPost.id ? updatedPost : p));
  };

  const deletePost = async (id: string) => {
    const { error } = await supabase.from('posts').delete().eq('id', id);
    if (error) throw error;
    setPosts(prev => prev.filter(p => p.id !== id));
  };

  const getPost = (id: string) => {
    return posts.find(p => p.id === id);
  };

  // Settings

  const updateSettings = async (newSettings: SiteSettings) => {
    // We assume ID 1 for single row settings
    const { error } = await supabase
      .from('site_settings')
      .update(newSettings)
      .eq('id', 1);

    if (error) throw error;
    setSettings(newSettings);
  };

  return (
    <PropertyContext.Provider value={{ 
      properties, leads, subscribers, posts, settings, isLoading,
      addProperty, updateProperty, deleteProperty, getProperty,
      addLead, updateLeadStatus, addSubscriber, updateSettings,
      addPost, updatePost, deletePost, getPost
    }}>
      {children}
    </PropertyContext.Provider>
  );
};

export const useProperties = () => {
  const context = useContext(PropertyContext);
  if (!context) {
    throw new Error('useProperties must be used within a PropertyProvider');
  }
  return context;
};

import React, { useRef, useEffect } from 'react';
import { 
  Bold, Italic, List, ListOrdered, AlignLeft, AlignCenter, AlignRight, 
  Heading1, Heading2, Quote, Link as LinkIcon, Undo, Redo
} from 'lucide-react';

interface RichTextEditorProps {
  value: string;
  onChange: (value: string) => void;
}

export const RichTextEditor: React.FC<RichTextEditorProps> = ({ value, onChange }) => {
  const editorRef = useRef<HTMLDivElement>(null);
  const isInternalChange = useRef(false);

  // Sync initial value or external updates to editor content
  useEffect(() => {
    if (editorRef.current && !isInternalChange.current && editorRef.current.innerHTML !== value) {
      editorRef.current.innerHTML = value;
    }
  }, [value]);

  const handleInput = () => {
    if (editorRef.current) {
      isInternalChange.current = true;
      onChange(editorRef.current.innerHTML);
      // Reset flag after a short delay to allow external updates again if needed
      setTimeout(() => isInternalChange.current = false, 0);
    }
  };

  const execCommand = (command: string, value: string | undefined = undefined) => {
    document.execCommand(command, false, value);
    // Ensure the editor keeps focus
    editorRef.current?.focus();
    handleInput();
  };

  const ToolbarButton = ({ 
    icon: Icon, 
    command, 
    arg = undefined, 
    title 
  }: { 
    icon: any, 
    command: string, 
    arg?: string, 
    title: string 
  }) => (
    <button
      type="button"
      onClick={() => execCommand(command, arg)}
      className="p-2 text-slate-600 hover:text-forge-navy hover:bg-slate-100 rounded transition-colors"
      title={title}
    >
      <Icon size={18} />
    </button>
  );

  return (
    <div className="border border-slate-200 rounded-sm overflow-hidden bg-white flex flex-col h-[500px]">
      {/* Toolbar */}
      <div className="flex flex-wrap items-center gap-1 p-2 bg-slate-50 border-b border-slate-200">
        <div className="flex items-center gap-1 border-r border-slate-200 pr-2 mr-1">
          <ToolbarButton icon={Undo} command="undo" title="Undo" />
          <ToolbarButton icon={Redo} command="redo" title="Redo" />
        </div>

        <div className="flex items-center gap-1 border-r border-slate-200 pr-2 mr-1">
          <ToolbarButton icon={Bold} command="bold" title="Bold" />
          <ToolbarButton icon={Italic} command="italic" title="Italic" />
        </div>

        <div className="flex items-center gap-1 border-r border-slate-200 pr-2 mr-1">
          <ToolbarButton icon={Heading1} command="formatBlock" arg="H2" title="Heading 1" />
          <ToolbarButton icon={Heading2} command="formatBlock" arg="H3" title="Heading 2" />
          <ToolbarButton icon={Quote} command="formatBlock" arg="BLOCKQUOTE" title="Quote" />
        </div>

        <div className="flex items-center gap-1 border-r border-slate-200 pr-2 mr-1">
          <ToolbarButton icon={AlignLeft} command="justifyLeft" title="Align Left" />
          <ToolbarButton icon={AlignCenter} command="justifyCenter" title="Align Center" />
          <ToolbarButton icon={AlignRight} command="justifyRight" title="Align Right" />
        </div>

        <div className="flex items-center gap-1">
           <ToolbarButton icon={List} command="insertUnorderedList" title="Bullet List" />
           <ToolbarButton icon={ListOrdered} command="insertOrderedList" title="Numbered List" />
        </div>
      </div>

      {/* Editor Area */}
      <div 
        ref={editorRef}
        className="flex-grow p-6 overflow-y-auto focus:outline-none prose max-w-none font-serif text-lg leading-relaxed text-slate-700"
        contentEditable
        onInput={handleInput}
        spellCheck={true}
      />

      <div className="bg-slate-50 border-t border-slate-100 p-2 text-[10px] text-slate-400 uppercase tracking-wider font-bold text-right px-4">
        Classic Editor Mode
      </div>
    </div>
  );
};

