const ScrollToTop = () => {
  const { pathname } = useLocation();

  React.useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);

  return null;
};

// Layout wrapper to conditionally render public UI
const AppLayout: React.FC = () => {
  const location = useLocation();
  // Check if the current route is an admin route
  const isAdminRoute = location.pathname.startsWith('/admin');

  return (
    <div className="flex flex-col min-h-screen font-sans bg-slate-50 text-slate-900 selection:bg-forge-gold selection:text-forge-navy">
      {/* Only show Public Navbar on non-admin pages */}
      {!isAdminRoute && <Navbar />}

      <main className="flex-grow">
        <Routes>
          {/* Public Routes */}
          <Route path="/" element={<Home />} />
          <Route path="/about" element={<About />} />
          <Route path="/listings" element={<Listings />} />
          <Route path="/listings/:id" element={<ListingDetails />} />
          <Route path="/blog" element={<Blog />} />
          <Route path="/blog/:id" element={<BlogPostDetails />} />
          <Route path="/contact" element={<Contact />} />

          {/* Admin Routes */}
          <Route path="/admin/login" element={<AdminLogin />} />
          <Route 
            path="/admin" 
            element={
              <ProtectedRoute>
                <Admin />
              </ProtectedRoute>
            } 
          />
          <Route 
            path="/admin/crm" 
            element={
              <ProtectedRoute>
                <AdminCRM />
              </ProtectedRoute>
            } 
          />
          <Route 
            path="/admin/analytics" 
            element={
              <ProtectedRoute>
                <AdminAnalytics />
              </ProtectedRoute>
            } 
          />
          <Route 
            path="/admin/settings" 
            element={
              <ProtectedRoute>
                <AdminSettings />
              </ProtectedRoute>
            } 
          />
           <Route 
            path="/admin/blog" 
            element={
              <ProtectedRoute>
                <AdminBlog />
              </ProtectedRoute>
            } 
          />
           <Route 
            path="/admin/blog/new" 
            element={
              <ProtectedRoute>
                <AdminPostForm />
              </ProtectedRoute>
            } 
          />
           <Route 
            path="/admin/blog/edit/:id" 
            element={
              <ProtectedRoute>
                <AdminPostForm />
              </ProtectedRoute>
            } 
          />
          <Route 
            path="/admin/properties/new" 
            element={
              <ProtectedRoute>
                <AdminPropertyForm />
              </ProtectedRoute>
            } 
          />
          <Route 
            path="/admin/properties/edit/:id" 
            element={
              <ProtectedRoute>
                <AdminPropertyForm />
              </ProtectedRoute>
            } 
          />

          {/* Fallback to Home for unmatched routes */}
          <Route path="*" element={<Home />} />
        </Routes>
      </main>

      {/* Only show Public Footer and AI Chat on non-admin pages */}
      {!isAdminRoute && <Footer />}
      {!isAdminRoute && <AIConcierge />}
    </div>
  );
};

const App: React.FC = () => {
  return (
    <PropertyProvider>
      <AuthProvider>
        <Router>
          <ScrollToTop />
          <AppLayout />
        </Router>
      </AuthProvider>
    </PropertyProvider>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
