import React, { useRef, useEffect, useState } from 'react';
import { 
  Bold, Italic, List, ListOrdered, AlignLeft, AlignCenter, AlignRight, 
  Quote, Undo, Redo, Code, Type
} from 'lucide-react';

interface RichTextEditorProps {
  value: string;
  onChange: (value: string) => void;
}

export const RichTextEditor: React.FC<RichTextEditorProps> = ({ value, onChange }) => {
  const editorRef = useRef<HTMLDivElement>(null);
  const isInternalChange = useRef(false);
  const [isCodeView, setIsCodeView] = useState(false);
  const [currentBlock, setCurrentBlock] = useState('P');

  // Sync initial value or external updates to editor content
  useEffect(() => {
    if (editorRef.current && !isInternalChange.current && !isCodeView && editorRef.current.innerHTML !== value) {
      editorRef.current.innerHTML = value;
    }
  }, [value, isCodeView]);

  const handleInput = () => {
    if (editorRef.current) {
      isInternalChange.current = true;
      onChange(editorRef.current.innerHTML);
      // Reset flag after a short delay to allow external updates again if needed
      setTimeout(() => isInternalChange.current = false, 0);
    }
  };

  const execCommand = (command: string, value: string | undefined = undefined) => {
    document.execCommand(command, false, value);
    // Ensure the editor keeps focus
    if (!isCodeView) {
      editorRef.current?.focus();
      handleInput();
    }
  };

  const handleBlockChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const val = e.target.value;
    setCurrentBlock(val);
    execCommand('formatBlock', val);
  };

  const toggleCodeView = () => {
    setIsCodeView(!isCodeView);
  };

  const ToolbarButton = ({ 
    icon: Icon, 
    command, 
    arg = undefined, 
    title,
    disabled = false
  }: { 
    icon: any, 
    command: string, 
    arg?: string, 
    title: string,
    disabled?: boolean
  }) => (
    <button
      type="button"
      onClick={() => execCommand(command, arg)}
      disabled={disabled}
      className={`p-2 rounded transition-colors ${
        disabled 
          ? 'text-slate-300 cursor-not-allowed' 
          : 'text-slate-600 hover:text-forge-navy hover:bg-slate-100'
      }`}
      title={title}
    >
      <Icon size={18} />
    </button>
  );

  return (
    <div className="border border-slate-200 rounded-sm overflow-hidden bg-white flex flex-col h-[600px]">
      {/* Toolbar */}
      <div className="flex flex-wrap items-center gap-1 p-2 bg-slate-50 border-b border-slate-200">

        {/* 1. Format Block Dropdown (First Item) */}
        <div className="flex items-center border-r border-slate-200 pr-2 mr-1">
          <Type size={18} className="text-slate-400 mr-2 ml-1" />
          <select 
            value={currentBlock}
            onChange={handleBlockChange}
            disabled={isCodeView}
            className="bg-transparent text-sm font-bold text-slate-700 focus:outline-none cursor-pointer py-1"
          >
            <option value="P">Normal Text</option>
            <option value="H2">Heading 1 (H2)</option>
            <option value="H3">Heading 2 (H3)</option>
            <option value="H4">Heading 3 (H4)</option>
            <option value="BLOCKQUOTE">Quote</option>
            <option value="PRE">Code Block</option>
          </select>
        </div>

        {/* 2. Standard Formatting */}
        <div className="flex items-center gap-1 border-r border-slate-200 pr-2 mr-1">
          <ToolbarButton icon={Bold} command="bold" title="Bold" disabled={isCodeView} />
          <ToolbarButton icon={Italic} command="italic" title="Italic" disabled={isCodeView} />
        </div>

        {/* 3. Alignment */}
        <div className="flex items-center gap-1 border-r border-slate-200 pr-2 mr-1">
          <ToolbarButton icon={AlignLeft} command="justifyLeft" title="Align Left" disabled={isCodeView} />
          <ToolbarButton icon={AlignCenter} command="justifyCenter" title="Align Center" disabled={isCodeView} />
          <ToolbarButton icon={AlignRight} command="justifyRight" title="Align Right" disabled={isCodeView} />
        </div>

        {/* 4. Lists & Quotes */}
        <div className="flex items-center gap-1 border-r border-slate-200 pr-2 mr-1">
           <ToolbarButton icon={List} command="insertUnorderedList" title="Bullet List" disabled={isCodeView} />
           <ToolbarButton icon={ListOrdered} command="insertOrderedList" title="Numbered List" disabled={isCodeView} />
           <ToolbarButton icon={Quote} command="formatBlock" arg="BLOCKQUOTE" title="Quote" disabled={isCodeView} />
        </div>

        {/* 5. Undo/Redo (Moved here) */}
        <div className="flex items-center gap-1">
          <ToolbarButton icon={Undo} command="undo" title="Undo" disabled={isCodeView} />
          <ToolbarButton icon={Redo} command="redo" title="Redo" disabled={isCodeView} />
        </div>

        {/* 6. Code View Toggle (Far Right) */}
        <div className="ml-auto flex items-center border-l border-slate-200 pl-2">
            <button
              type="button"
              onClick={toggleCodeView}
              className={`flex items-center gap-2 px-3 py-1.5 rounded text-xs font-bold uppercase tracking-wider transition-colors ${
                isCodeView 
                  ? 'bg-forge-navy text-white' 
                  : 'text-slate-500 hover:bg-slate-200'
              }`}
            >
              <Code size={14} />
              {isCodeView ? 'Visual' : 'Code'}
            </button>
        </div>
      </div>

      {/* Editor Area */}
      {isCodeView ? (
        <textarea
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="flex-grow p-6 w-full h-full bg-slate-900 text-green-400 font-mono text-sm leading-relaxed focus:outline-none resize-none"
          spellCheck={false}
        />
      ) : (
        <div 
          ref={editorRef}
          className="flex-grow p-6 overflow-y-auto focus:outline-none prose max-w-none font-serif text-lg leading-relaxed text-slate-700"
          contentEditable
          onInput={handleInput}
          spellCheck={true}
        />
      )}

      <div className="bg-slate-50 border-t border-slate-100 p-2 text-[10px] text-slate-400 uppercase tracking-wider font-bold text-right px-4 flex justify-between items-center">
        <span>{isCodeView ? 'HTML SOURCE MODE' : 'VISUAL EDITOR MODE'}</span>
        <span>{value.length} Characters</span>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { 
  ArrowLeft, Save, Upload, Image as ImageIcon, Loader2, CheckCircle, Plus, Search, Globe, FileText, X
} from 'lucide-react';
import { useProperties } from '../context/PropertyContext';
import { BlogPost } from '../types';
import { AdminLayout } from '../components/AdminLayout';
import { RichTextEditor } from '../components/RichTextEditor';
import { resizeImage } from '../utils/imageUtils';

export const AdminPostForm: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { getPost, addPost, updatePost, settings } = useProperties();
  const isEditing = !!id;
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState('');

  // Ref for hidden file input
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Category State
  const [categories, setCategories] = useState(['Market Insights', 'Luxury Lifestyle', 'Company News', 'Investment']);
  const [isAddingCategory, setIsAddingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');

  const [formData, setFormData] = useState<BlogPost>({
    id: '',
    title: '',
    excerpt: '',
    content: '',
    coverImage: '',
    author: settings.teamMembers[0]?.name || 'Admin',
    date: new Date().toISOString(),
    category: 'Market Insights',
    status: 'Draft',
    metaDescription: '',
    keyphrase: ''
  });

  useEffect(() => {
    if (isEditing && id) {
      const post = getPost(id);
      if (post) {
        setFormData(post);
        // If post has a category not in our default list, add it
        if (!categories.includes(post.category)) {
          setCategories(prev => [...prev, post.category]);
        }
      }
    } else if (!isEditing) {
      setFormData(prev => prev.id ? prev : ({ ...prev, id: Date.now().toString() }));
    }
  }, [id, isEditing, getPost, categories]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleContentChange = (content: string) => {
    setFormData(prev => ({ ...prev, content }));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      try {
        const base64String = await resizeImage(file);
        setFormData(prev => ({ ...prev, coverImage: base64String }));
      } catch (err) {
        setError("Failed to process image.");
      }
    }
  };

  const handleAddCategory = () => {
    if (newCategoryName.trim()) {
      setCategories(prev => [...prev, newCategoryName]);
      setFormData(prev => ({ ...prev, category: newCategoryName }));
      setNewCategoryName('');
      setIsAddingCategory(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent, statusOverride?: 'Published' | 'Draft') => {
    e.preventDefault();
    setIsSubmitting(true);
    setError('');

    const finalStatus = statusOverride || formData.status;
    const submissionData = { ...formData, status: finalStatus };

    try {
      if (isEditing) {
        await updatePost(submissionData);
      } else {
        await addPost(submissionData);
      }
      setIsSuccess(true);
      setTimeout(() => {
        navigate('/admin/blog');
      }, 1000);
    } catch (err) {
      console.error(err);
      setError("Failed to save post.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <AdminLayout>
      <div className="max-w-6xl mx-auto">
        <div className="flex items-center gap-4 mb-6">
            <button 
              onClick={() => navigate('/admin/blog')}
              className="text-slate-400 hover:text-forge-navy transition-colors flex items-center gap-2 text-sm font-medium"
            >
              <ArrowLeft size={16} /> Back to Blog
            </button>
        </div>

        <form className="flex flex-col lg:flex-row gap-8">
           {/* Main Content Area */}
           <div className="flex-1 space-y-8">
              {/* Title */}
              <div>
                <input
                  type="text"
                  name="title"
                  value={formData.title}
                  onChange={handleChange}
                  className="w-full bg-transparent border-0 border-b-2 border-slate-200 py-4 text-3xl md:text-4xl font-serif font-bold text-forge-navy focus:border-forge-gold focus:outline-none placeholder-slate-300 transition-colors"
                  placeholder="Enter Title Here"
                  required
                />
              </div>

              {/* Editor */}
              <div>
                <RichTextEditor value={formData.content} onChange={handleContentChange} />
              </div>

              {/* Excerpt */}
              <div className="bg-white p-6 shadow-sm border border-slate-200 rounded-sm">
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-3 flex items-center gap-2">
                   <FileText size={14} /> Short Excerpt
                </label>
                <textarea
                  name="excerpt"
                  value={formData.excerpt}
                  onChange={handleChange}
                  rows={3}
                  className="w-full bg-slate-50 border border-slate-200 p-4 text-sm focus:border-forge-gold focus:outline-none transition-colors rounded-sm"
                  placeholder="A brief summary for the preview card..."
                />
              </div>

              {/* SEO Configuration */}
              <div className="bg-white p-6 shadow-sm border border-slate-200 rounded-sm">
                 <div className="flex items-center gap-2 mb-4 border-b border-slate-100 pb-3">
                   <Globe size={16} className="text-forge-gold" />
                   <h3 className="text-sm font-bold uppercase tracking-widest text-slate-600">SEO Configuration</h3>
                 </div>

                 <div className="space-y-4">
                    <div>
                      <label className="block text-xs font-bold text-slate-500 mb-1">Focus Keyphrase</label>
                      <input 
                        type="text"
                        name="keyphrase"
                        value={formData.keyphrase || ''}
                        onChange={handleChange}
                        placeholder="e.g. Luxury Real Estate Lagos"
                        className="w-full border border-slate-200 p-3 text-sm rounded bg-slate-50 focus:border-forge-gold focus:outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-slate-500 mb-1">Meta Description</label>
                      <textarea
                        name="metaDescription"
                        value={formData.metaDescription || ''}
                        onChange={handleChange}
                        rows={2}
                        maxLength={160}
                        placeholder="A concise summary for search engines (max 160 chars)"
                        className="w-full border border-slate-200 p-3 text-sm rounded bg-slate-50 focus:border-forge-gold focus:outline-none resize-none"
                      />
                      <p className="text-[10px] text-right text-slate-400 mt-1">
                        {(formData.metaDescription?.length || 0)} / 160 characters
                      </p>
                    </div>
                 </div>
              </div>
           </div>

           {/* Sidebar Options */}
           <div className="w-full lg:w-80 space-y-6">

              {/* Publish Actions */}
              <div className="bg-white p-6 shadow-sm border border-slate-200 rounded-sm sticky top-6 z-10">
                <h3 className="text-xs font-bold uppercase tracking-widest text-slate-500 mb-4">Publish</h3>
                <div className="space-y-4">
                  <div className="flex justify-between items-center text-sm text-slate-600 border-b border-slate-100 pb-2">
                    <span>Status:</span>
                    <span className="font-bold">{formData.status}</span>
                  </div>
                  <div className="flex justify-between items-center text-sm text-slate-600 border-b border-slate-100 pb-2">
                    <span>Visibility:</span>
                    <span className="font-bold">Public</span>
                  </div>

                  <div className="grid grid-cols-2 gap-3 mt-4">
                    <button
                      type="button"
                      onClick={(e) => handleSubmit(e, 'Draft')}
                      disabled={isSubmitting || isSuccess}
                      className="py-3 px-2 border border-slate-300 text-slate-600 font-bold uppercase tracking-widest text-[10px] rounded-sm hover:bg-slate-50 transition-colors"
                    >
                       Save Draft
                    </button>
                    <button
                      type="button"
                      onClick={(e) => handleSubmit(e, 'Published')}
                      disabled={isSubmitting || isSuccess}
                      className="py-3 px-2 bg-forge-navy text-white font-bold uppercase tracking-widest text-[10px] rounded-sm hover:bg-forge-dark transition-colors"
                    >
                       Publish
                    </button>
                  </div>

                  {(isSubmitting || isSuccess) && (
                    <div className="flex items-center justify-center gap-2 text-xs font-bold text-forge-gold mt-2">
                        {isSubmitting ? <Loader2 size={14} className="animate-spin" /> : <CheckCircle size={14} />}
                        {isSubmitting ? 'Saving...' : 'Saved!'}
                    </div>
                  )}
                  {error && <p className="text-red-500 text-xs text-center">{error}</p>}
                </div>
              </div>

              {/* Category */}
              <div className="bg-white p-6 shadow-sm border border-slate-200 rounded-sm">
                 <h3 className="text-xs font-bold uppercase tracking-widest text-slate-500 mb-4">Category</h3>

                 {isAddingCategory ? (
                   <div className="space-y-2 animate-fade-in">
                     <input 
                       type="text" 
                       value={newCategoryName}
                       onChange={(e) => setNewCategoryName(e.target.value)}
                       className="w-full border border-slate-300 p-2 text-sm focus:border-forge-gold focus:outline-none"
                       placeholder="New Category Name"
                       autoFocus
                     />
                     <div className="flex gap-2">
                       <button 
                         type="button"
                         onClick={handleAddCategory}
                         className="flex-1 bg-forge-navy text-white text-xs font-bold py-2 rounded-sm"
                       >
                         Add
                       </button>
                       <button 
                         type="button"
                         onClick={() => setIsAddingCategory(false)}
                         className="px-2 border border-slate-300 text-slate-500 rounded-sm hover:bg-slate-100"
                       >
                         <X size={14} />
                       </button>
                     </div>
                   </div>
                 ) : (
                   <div className="space-y-3">
                      <select 
                        name="category"
                        value={formData.category}
                        onChange={handleChange}
                        className="w-full border border-slate-200 p-2.5 text-sm rounded bg-slate-50 focus:border-forge-gold focus:outline-none"
                      >
                        {categories.map(cat => (
                          <option key={cat} value={cat}>{cat}</option>
                        ))}
                      </select>

                      <button 
                        type="button"
                        onClick={() => setIsAddingCategory(true)}
                        className="text-forge-gold text-xs font-bold hover:underline flex items-center gap-1"
                      >
                        <Plus size={12} /> Add New Category
                      </button>
                   </div>
                 )}
              </div>

              {/* Author */}
              <div className="bg-white p-6 shadow-sm border border-slate-200 rounded-sm">
                 <h3 className="text-xs font-bold uppercase tracking-widest text-slate-500 mb-4">Author</h3>
                 <input
                    type="text"
                    name="author"
                    value={formData.author}
                    onChange={handleChange}
                    className="w-full border border-slate-200 p-2 text-sm rounded bg-slate-50"
                  />
              </div>

              {/* Featured Image */}
              <div className="bg-white p-6 shadow-sm border border-slate-200 rounded-sm">
                 <h3 className="text-xs font-bold uppercase tracking-widest text-slate-500 mb-4">Featured Image</h3>
                 <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="aspect-video bg-slate-100 border-2 border-dashed border-slate-300 rounded flex flex-col items-center justify-center cursor-pointer hover:border-forge-gold overflow-hidden relative"
                 >
                    {formData.coverImage ? (
                      <img src={formData.coverImage} alt="Cover" className="w-full h-full object-cover" />
                    ) : (
                      <>
                        <ImageIcon size={24} className="text-slate-400 mb-2" />
                        <span className="text-xs text-slate-400">Click to Upload</span>
                      </>
                    )}
                 </div>
                 <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept="image/*"
                    onChange={handleFileUpload} 
                  />
                  {formData.coverImage && (
                    <button 
                      type="button"
                      onClick={() => setFormData(prev => ({...prev, coverImage: ''}))}
                      className="text-red-500 text-xs mt-2 underline"
                    >
                      Remove Image
                    </button>
                  )}
              </div>

           </div>
        </form>
      </div>
    </AdminLayout>
  );
};

