export const PropertyProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [properties, setProperties] = useState<Property[]>([]);
  const [leads, setLeads] = useState<Lead[]>([]);
  const [subscribers, setSubscribers] = useState<Subscriber[]>([]);
  const [posts, setPosts] = useState<BlogPost[]>([]);
  const [settings, setSettings] = useState<SiteSettings>(DEFAULT_SETTINGS);
  const [isLoading, setIsLoading] = useState(true);

  // Fetch Initial Data from Supabase
  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);
      try {
        const [propsRes, leadsRes, subsRes, postsRes, settingsRes] = await Promise.all([
          supabase.from('properties').select('*'),
          supabase.from('leads').select('*'),
          supabase.from('subscribers').select('*'),
          supabase.from('posts').select('*'),
          supabase.from('site_settings').select('*').single()
        ]);

        if (propsRes.data) setProperties(propsRes.data);
        if (leadsRes.data) setLeads(leadsRes.data);
        if (subsRes.data) setSubscribers(subsRes.data);

        // Add sample post if list is empty for testing purposes
        if (postsRes.data && postsRes.data.length > 0) {
          setPosts(postsRes.data);
        } else {
          setPosts([SAMPLE_POST]);
        }

        if (settingsRes.data) {
          // Merge with default to ensure new fields (like listingAgent) exist if not in DB yet
          setSettings({ ...DEFAULT_SETTINGS, ...settingsRes.data });
        } else {
            // Use defaults if table is empty
            setSettings(DEFAULT_SETTINGS); 
        }

      } catch (error) {
        console.error('Error fetching data from Supabase:', error);
        // On error, still load sample post for testing
        setPosts([SAMPLE_POST]);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []);

  // CRUD Operations - Properties

  const addProperty = async (property: Property) => {
    const { error } = await supabase.from('properties').insert([property]);
    if (error) throw error;
    setProperties(prev => [property, ...prev]);
  };

  const updateProperty = async (updatedProperty: Property) => {
    const { error } = await supabase
      .from('properties')
      .update(updatedProperty)
      .eq('id', updatedProperty.id);

    if (error) throw error;
    setProperties(prev => prev.map(p => p.id === updatedProperty.id ? updatedProperty : p));
  };

  const deleteProperty = async (id: string) => {
    const { error } = await supabase.from('properties').delete().eq('id', id);
    if (error) throw error;
    setProperties(prev => prev.filter(p => p.id !== id));
  };

  const getProperty = (id: string) => {
    return properties.find(p => p.id === id);
  };

  // CRUD Operations - Leads

  const addLead = async (lead: Lead) => {
    const { error } = await supabase.from('leads').insert([lead]);
    if (error) throw error;
    setLeads(prev => [lead, ...prev]);
  };

  const updateLeadStatus = async (id: string, status: Lead['status']) => {
    const { error } = await supabase.from('leads').update({ status }).eq('id', id);
    if (error) throw error;
    setLeads(prev => prev.map(l => l.id === id ? { ...l, status } : l));
  };

  // CRUD Operations - Subscribers

  const addSubscriber = async (email: string) => {
    if (subscribers.some(s => s.email === email)) return;

    const newSubscriber: Subscriber = {
      id: Date.now().toString(),
      email,
      date: new Date().toISOString()
    };

    // 1. Add to Supabase
    const { error } = await supabase.from('subscribers').insert([newSubscriber]);
    if (error) throw error;
    setSubscribers(prev => [newSubscriber, ...prev]);

    // 2. Sync with MailerLite
    try {
      await fetch('https://connect.mailerlite.com/api/subscribers', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${MAILERLITE_API_KEY}`,
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          email: email,
        })
      });
    } catch (err) {
      console.warn("MailerLite sync issue:", err);
    }
  };

  // CRUD Operations - Blog Posts

  const addPost = async (post: BlogPost) => {
    const { error } = await supabase.from('posts').insert([post]);
    if (error) throw error;
    setPosts(prev => [post, ...prev]);
  };

  const updatePost = async (updatedPost: BlogPost) => {
    // If it's the sample post, just update local state to simulate success for testing
    if (updatedPost.id === 'sample-1') {
        setPosts(prev => prev.map(p => p.id === updatedPost.id ? updatedPost : p));
        return;
    }

    const { error } = await supabase
      .from('posts')
      .update(updatedPost)
      .eq('id', updatedPost.id);

    if (error) throw error;
    setPosts(prev => prev.map(p => p.id === updatedPost.id ? updatedPost : p));
  };

  const deletePost = async (id: string) => {
    // If it's the sample post, just update local state
    if (id === 'sample-1') {
        setPosts(prev => prev.filter(p => p.id !== id));
        return;
    }

    const { error } = await supabase.from('posts').delete().eq('id', id);
    if (error) throw error;
    setPosts(prev => prev.filter(p => p.id !== id));
  };

  const getPost = (id: string) => {
    return posts.find(p => p.id === id);
  };

  // Settings

  const updateSettings = async (newSettings: SiteSettings) => {
    // We assume ID 1 for single row settings
    const { error } = await supabase
      .from('site_settings')
      .update(newSettings)
      .eq('id', 1);

    if (error) throw error;
    setSettings(newSettings);
  };

  return (
    <PropertyContext.Provider value={{ 
      properties, leads, subscribers, posts, settings, isLoading,
      addProperty, updateProperty, deleteProperty, getProperty,
      addLead, updateLeadStatus, addSubscriber, updateSettings,
      addPost, updatePost, deletePost, getPost
    }}>
      {children}
    </PropertyContext.Provider>
  );
};

export const useProperties = () => {
  const context = useContext(PropertyContext);
  if (!context) {
    throw new Error('useProperties must be used within a PropertyProvider');
  }
  return context;
};

import React, { useEffect } from 'react';

interface SEOProps {
  title: string;
  description?: string;
  keywords?: string;
  image?: string;
  url?: string;
  type?: 'website' | 'article' | 'realestate';
  schema?: object;
}

export const SEO: React.FC<SEOProps> = ({ 
  title, 
  description, 
  keywords, 
  image, 
  url, 
  type = 'website',
  schema 
}) => {
  const siteName = 'The Forge Properties';
  const fullTitle = `${title} | ${siteName}`;
  const defaultDesc = 'The Forge Properties is the premier luxury real estate division of The Forge Group. Discover exclusive villas, penthouses, and estates in Nigeria.';
  const defaultKeywords = 'luxury real estate nigeria, lagos property, banana island homes, the forge properties, real estate investment nigeria';
  const defaultImage = 'https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?q=80&w=1200';
  const canonicalUrl = url ? `https://theforgeproperties.com${url}` : window.location.href;

  useEffect(() => {
    // Basic Meta
    document.title = fullTitle;

    const updateMeta = (name: string, content: string, attr: 'name' | 'property' = 'name') => {
      let element = document.querySelector(`meta[${attr}="${name}"]`);
      if (!element) {
        element = document.createElement('meta');
        element.setAttribute(attr, name);
        document.head.appendChild(element);
      }
      element.setAttribute('content', content);
    };

    updateMeta('description', description || defaultDesc);
    updateMeta('keywords', keywords || defaultKeywords);

    // Open Graph / Social
    updateMeta('og:title', fullTitle, 'property');
    updateMeta('og:description', description || defaultDesc, 'property');
    updateMeta('og:image', image || defaultImage, 'property');
    updateMeta('og:url', canonicalUrl, 'property');
    updateMeta('og:type', type === 'article' ? 'article' : 'website', 'property');
    updateMeta('og:site_name', siteName, 'property');

    // Twitter
    updateMeta('twitter:card', 'summary_large_image');
    updateMeta('twitter:title', fullTitle);
    updateMeta('twitter:description', description || defaultDesc);
    updateMeta('twitter:image', image || defaultImage);

    // Canonical
    let link: HTMLLinkElement | null = document.querySelector('link[rel="canonical"]');
    if (!link) {
      link = document.createElement('link');
      link.setAttribute('rel', 'canonical');
      document.head.appendChild(link);
    }
    link.setAttribute('href', canonicalUrl);

    // JSON-LD Schema
    const existingScript = document.getElementById('json-ld-schema');
    if (existingScript) existingScript.remove();

    if (schema) {
      const script = document.createElement('script');
      script.id = 'json-ld-schema';
      script.type = 'application/ld+json';
      script.text = JSON.stringify({
        "@context": "https://schema.org",
        ...schema
      });
      document.head.appendChild(script);
    }

    return () => {
      // Cleanup if needed when unmounting
    };
  }, [fullTitle, description, keywords, image, canonicalUrl, type, schema]);

  return null; // This component doesn't render anything visible
};

