        handleMemberChange(index, 'image', base64String);
      } catch (err) {
        setError('Failed to process image.');
      }
    }
  };

  const handleAgentImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
