  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { getProperty, addProperty, updateProperty, settings, isLoading } = useProperties();
  const isEditing = !!id;

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [error, setError] = useState('');
  const [isSuccess, setIsSuccess] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const agentFileInputRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState<Property>({
    id: '',
    slug: '',
    title: '',
    description: '',
    price: 0,
    location: '',
    bedrooms: 0,
    bathrooms: 0,
    area_sq_ft: 0,
    type: PropertyType.VILLA,
    status: ListingStatus.FOR_SALE,
    images: [],
    features: [],
    agent: {
      name: settings?.listing_agent?.name || 'The Forge Properties',
      image: settings?.listing_agent?.image || '',
      phone: settings?.listing_agent?.phone || '+234 800 FORGE 00'
    },
    featured: false
  });

  const [featuresInput, setFeaturesInput] = useState('');

  const slugify = (text: string) => {
    return text.toString().toLowerCase().trim()
      .replace(/\s+/g, '-')
      .replace(/[^\w-]+/g, '')
      .replace(/--+/g, '-')
      .replace(/^-+/, '')
      .replace(/-+$/, '');
  };

  useEffect(() => {
    if (!isLoading) {
      if (isEditing && id) {
        const property = getProperty(id);
        if (property) {
          setFormData(property);
          setFeaturesInput(property.features.join(', '));
        } else {
          setError("Property not found.");
        }
      } else if (!isEditing) {
        setFormData(prev => ({ 
          ...prev, 
          id: Date.now().toString(),
          agent: {
            name: settings?.listing_agent?.name || 'The Forge Properties',
            image: settings?.listing_agent?.image || '',
            phone: settings?.listing_agent?.phone || '+234 800 FORGE 00'
          }
        }));
      }
    }
  }, [id, isEditing, getProperty, isLoading, settings]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target;
    const val = type === 'number' ? parseFloat(value) : (type === 'checkbox' ? (e.target as HTMLInputElement).checked : value);

    setFormData(prev => {
      const updated = { ...prev, [name]: val };
      if (name === 'title' && (!prev.slug || prev.slug === slugify(prev.title))) {
        updated.slug = slugify(value);
      }
      return updated;
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsUploading(true);
    setError('');

    const newImageUrls: string[] = [...formData.images];

    try {
      for (let i = 0; i < files.length; i++) {
        const resizedBase64 = await resizeImage(files[i]);
        const blob = dataURLtoBlob(resizedBase64);
        const fileName = `${Date.now()}-${files[i].name.replace(/[^a-zA-Z0-9.]/g, '_')}`;

        // Upload to Supabase Storage
        const publicUrl = await uploadImage('property-images', fileName, blob);
        newImageUrls.push(publicUrl);
      }
      setFormData({ ...formData, images: newImageUrls });
    } catch (err: any) {
      setError(`Upload failed: ${err.message}. Ensure 'property-images' bucket exists and is public.`);
    } finally {
      setIsUploading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const removeImage = (index: number) => {
    const newImages = [...formData.images];
    newImages.splice(index, 1);
    setFormData({ ...formData, images: newImages });
  };

  const handleAgentImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    try {
      const resizedBase64 = await resizeImage(file, 400, 400);
      const blob = dataURLtoBlob(resizedBase64);
      const fileName = `agent-${Date.now()}-${file.name}`;
      const publicUrl = await uploadImage('property-images', fileName, blob);
      setFormData({ ...formData, agent: { ...formData.agent, image: publicUrl } });
    } catch (err: any) {
      setError(`Agent photo upload failed: ${err.message}`);
    } finally {
      setIsUploading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isUploading) return;
    setIsSubmitting(true);
    setError('');

    const finalFeatures = featuresInput.split(',').map(f => f.trim()).filter(f => f !== '');
