import React from 'react';
import { DollarSign, Home, Users, TrendingUp, Activity, MapPin } from 'lucide-react';
import { useProperties } from '../context/PropertyContext';
import { AdminLayout } from '../components/AdminLayout';

export const AdminAnalytics: React.FC = () => {
  const { properties, leads } = useProperties();

  // Strict cleanup of artifacts
  const validLeads = leads.filter(l => 
    l.name && 
    l.name.trim() !== '' && 
    l.name !== 'Chief Adewale' && 
    l.email !== 'test@example.com'
  );

  // Metrics
  const totalValue = properties.reduce((sum, p) => sum + (p.price || 0), 0);
  const activeListings = properties.filter(p => p.status === 'For Sale' || p.status === 'For Rent').length;
  const soldListings = properties.filter(p => p.status === 'Sold').length;
  const totalLeadsCount = validLeads.length;
  const newLeads = validLeads.filter(l => l.status === 'New').length;
  const closedLeads = validLeads.filter(l => l.status === 'Closed').length;

  // Conversion rate should be 0 if no leads
  const conversionRate = totalLeadsCount > 0 ? (closedLeads / totalLeadsCount) * 100 : 0;

  // Calculate Inventory by Location
  const locationStats = properties.reduce((acc: Record<string, number>, curr) => {
    const city = curr.location.split(',')[0].trim();
    acc[city] = (acc[city] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const totalProps = properties.length;
  const sortedLocations = Object.entries(locationStats)
    .sort((a, b) => (b[1] as number) - (a[1] as number))
    .slice(0, 5)
    .map(([loc, count]) => ({
      loc,
      count: count as number,
      percent: totalProps > 0 ? Math.round(((count as number) / totalProps) * 100) : 0
    }));

  const colors = ['bg-forge-navy', 'bg-forge-gold', 'bg-slate-400', 'bg-blue-500', 'bg-green-500'];

  const activityLog = [
    ...validLeads.map(l => ({
      type: 'lead',
      date: new Date(l.date).getTime(),
      user: 'System',
      action: `New ${l.type.toLowerCase()}`,
      target: l.name,
      displayTime: l.date
    })),
    ...properties.map(p => {
      let date = Date.now();
      if (p.id.length > 10 && !isNaN(Number(p.id))) {
        date = Number(p.id);
      } 
      return {
        type: 'property',
        date,
        user: 'Admin',
        action: 'Property listed',
        target: p.title,
        displayTime: new Date(date).toLocaleDateString()
      };
    })
  ].sort((a, b) => b.date - a.date).slice(0, 8);

  return (
    <AdminLayout>
      <div className="max-w-6xl">
        <h1 className="text-3xl font-serif text-forge-navy mb-8">Performance Analytics</h1>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-12">
          <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
            <div className="flex items-center gap-4 mb-2">
              <div className="p-3 bg-green-50 text-green-600 rounded-full"><DollarSign size={20} /></div>
              <span className="text-slate-500 text-xs font-bold uppercase tracking-widest">Portfolio Value</span>
            </div>
            <h3 className="text-2xl font-bold text-forge-navy truncate">₦{(totalValue / 1000000000).toFixed(2)}B</h3>
            <p className="text-xs text-green-600 mt-1 flex items-center gap-1"><TrendingUp size={12} /> Live Valuation</p>
          </div>

          <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
            <div className="flex items-center gap-4 mb-2">
              <div className="p-3 bg-blue-50 text-blue-600 rounded-full"><Home size={20} /></div>
              <span className="text-slate-500 text-xs font-bold uppercase tracking-widest">Active Listings</span>
            </div>
            <h3 className="text-2xl font-bold text-forge-navy">{activeListings}</h3>
            <p className="text-xs text-slate-400 mt-1">{soldListings} properties sold Total</p>
          </div>

          <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
            <div className="flex items-center gap-4 mb-2">
              <div className="p-3 bg-orange-50 text-orange-600 rounded-full"><Users size={20} /></div>
              <span className="text-slate-500 text-xs font-bold uppercase tracking-widest">Total Leads</span>
            </div>
            <h3 className="text-2xl font-bold text-forge-navy">{totalLeadsCount}</h3>
            <p className="text-xs text-orange-600 mt-1">{newLeads} new (pending)</p>
          </div>

          <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
             <div className="flex items-center gap-4 mb-2">
              <div className="p-3 bg-purple-50 text-purple-600 rounded-full"><TrendingUp size={20} /></div>
              <span className="text-slate-500 text-xs font-bold uppercase tracking-widest">Conversion Rate</span>
            </div>
            <h3 className="text-2xl font-bold text-forge-navy">
              {conversionRate.toFixed(1)}%
            </h3>
            <p className="text-xs text-slate-400 mt-1">{closedLeads} leads closed</p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
           <div className="bg-white p-8 rounded-lg shadow-sm border border-slate-200">
             <div className="flex items-center justify-between mb-6">
                <h3 className="font-serif text-lg text-forge-navy">Inventory by Location</h3>
                <MapPin size={18} className="text-slate-400" />
             </div>

             {sortedLocations.length > 0 ? (
               <div className="space-y-4">
                 {sortedLocations.map((item, i) => (
                   <div key={i}>
                      <div className="flex justify-between text-sm mb-1">
                        <span className="font-bold text-slate-600">{item.loc}</span>
                        <span className="text-slate-400">{item.percent}% ({item.count})</span>
                      </div>
                      <div className="w-full bg-slate-100 rounded-full h-2">
                        <div className={`h-2 rounded-full ${colors[i % colors.length]}`} style={{ width: `${item.percent}%` }}></div>
                      </div>
                   </div>
                 ))}
               </div>
             ) : (
               <div className="text-center text-slate-400 py-12">No inventory data available.</div>
             )}
           </div>

           <div className="bg-white p-8 rounded-lg shadow-sm border border-slate-200">
             <div className="flex items-center justify-between mb-6">
               <h3 className="font-serif text-lg text-forge-navy">Recent Activity Log</h3>
               <Activity size={18} className="text-slate-400" />
             </div>

             {activityLog.length > 0 ? (
               <div className="space-y-6">
                  {activityLog.map((log, i) => (
                    <div key={i} className="flex gap-4 items-start border-b border-slate-50 pb-4 last:border-0 last:pb-0">
                      <div className={`w-2 h-2 mt-2 rounded-full shrink-0 ${log.type === 'lead' ? 'bg-orange-400' : 'bg-forge-gold'}`}></div>
                      <div>
                        <p className="text-sm font-bold text-forge-navy">{log.action}</p>
                        <p className="text-xs text-slate-500">
                          {log.target} • <span className="text-slate-400">{log.displayTime}</span>
                        </p>
                      </div>
                    </div>
                  ))}
               </div>
             ) : (
               <div className="text-center text-slate-400 py-12">No recent activity.</div>
             )}
           </div>
        </div>
      </div>
    </AdminLayout>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { 
  ArrowLeft, CheckCircle, Image as ImageIcon, Loader2, Link as LinkIcon, 
  AlertCircle, Eye, Globe, Settings, FileText, Search
} from 'lucide-react';
import { useProperties } from '../context/PropertyContext';
import { BlogPost } from '../types';
import { AdminLayout } from '../components/AdminLayout';
import { RichTextEditor } from '../components/RichTextEditor';
import { resizeImage, dataURLtoBlob } from '../utils/imageUtils';
import { uploadImage } from '../lib/supabaseClient';

export const AdminPostForm: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { getPost, addPost, updatePost, isLoading } = useProperties();
  const isEditing = !!id;

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState('');
  const [dataLoaded, setDataLoaded] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [categories] = useState(['Market Insights', 'Luxury Lifestyle', 'Company News', 'Investment']);

  const [formData, setFormData] = useState<BlogPost>({
    id: '',
    slug: '',
    title: '',
    excerpt: '',
    content: '',
    cover_image: '',
    author: 'The Forge Properties',
    date: new Date().toISOString(),
    category: 'Market Insights',
    status: 'Draft',
    meta_description: '',
    keyphrase: ''
  });

  const slugify = (text: string) => {
    return text.toString().toLowerCase().trim()
      .replace(/\s+/g, '-')
      .replace(/[^\w-]+/g, '')
      .replace(/--+/g, '-')
      .replace(/^-+/, '')
      .replace(/-+$/, '');
  };

  useEffect(() => {
    if (!isLoading) {
      if (isEditing && id) {
        const post = getPost(id);
        if (post) {
          setFormData(post);
          setDataLoaded(true);
        } else {
          setError("Post not found.");
        }
      } else {
        setFormData({
          id: Date.now().toString(), slug: '', title: '', excerpt: '', content: '',
          cover_image: '', author: 'The Forge Properties', date: new Date().toISOString(),
          category: 'Market Insights', status: 'Draft', meta_description: '', keyphrase: ''
        });
        setDataLoaded(true);
      }
    }
  }, [id, isEditing, getPost, isLoading]);

  const handleTitleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newTitle = e.target.value;
    setFormData(prev => ({
      ...prev,
      title: newTitle,
      slug: (!prev.slug || prev.slug === slugify(prev.title)) ? slugify(newTitle) : prev.slug
    }));
  };

  const handleCoverUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    setError('');
    try {
      const resizedBase64 = await resizeImage(file, 1200, 630);
      const blob = dataURLtoBlob(resizedBase64);
      const fileName = `blog-${Date.now()}-${file.name.replace(/[^a-zA-Z0-9.]/g, '_')}`;
      const publicUrl = await uploadImage('blog-images', fileName, blob);
      setFormData({ ...formData, cover_image: publicUrl });
    } catch (err: any) {
      setError(`Upload failed: ${err.message}. Ensure 'blog-images' bucket is public.`);
    } finally {
      setIsUploading(false);
    }
  };

  const handleSave = async (e: React.FormEvent, statusOverride?: 'Published' | 'Draft') => {
    e.preventDefault();
    if (!formData.title.trim()) {
      setError("Article title is required.");
      return;
    }

    setIsSubmitting(true);
    setError('');

    const submissionData = { 
      ...formData, 
      status: statusOverride || formData.status,
      slug: formData.slug || slugify(formData.title)
    };

    try {
      if (isEditing) await updatePost(submissionData);
      else await addPost(submissionData);
      setIsSuccess(true);
      setTimeout(() => navigate('/admin/blog'), 1200);
    } catch (err: any) {
      setError(err.message || "Failed to save post.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isLoading || (isEditing && !dataLoaded)) {
    return (
      <AdminLayout>
        <div className="flex flex-col items-center justify-center min-h-[50vh]">
          <Loader2 size={32} className="animate-spin text-forge-gold mb-4" />
          <p className="font-serif italic text-slate-400">Loading Article...</p>
        </div>
      </AdminLayout>
    );
  }

  return (
    <AdminLayout>
      <div className="max-w-[1400px] mx-auto pb-20">
        <div className="flex items-center justify-between mb-6">
          <h1 className="text-2xl font-serif font-bold text-forge-navy">
            {isEditing ? 'Edit Post' : 'Add New Post'}
          </h1>
          <button onClick={() => navigate('/admin/blog')} className="text-slate-400 hover:text-forge-navy flex items-center gap-2 text-xs font-bold uppercase tracking-widest">
            <ArrowLeft size={14} /> Back
          </button>
        </div>

        {error && (
          <div className="bg-red-50 text-red-700 p-4 rounded mb-6 text-sm border border-red-200 flex items-center gap-2">
            <AlertCircle size={16} /> {error}
          </div>
        )}

        <form onSubmit={(e) => handleSave(e)} className="flex flex-col lg:flex-row gap-8">
          {/* Main Content Area (WordPress Left Column) */}
          <div className="flex-1 space-y-6">
            <input 
              type="text" 
              value={formData.title} 
              onChange={handleTitleChange} 
              placeholder="Enter title here"
              className="w-full bg-white border border-slate-200 p-4 text-2xl font-serif font-bold focus:border-forge-gold focus:outline-none shadow-sm"
              required
            />

            <div className="bg-white border border-slate-200 shadow-sm">
              <RichTextEditor value={formData.content} onChange={(content) => setFormData({...formData, content})} />
            </div>

            <div className="bg-white border border-slate-200 p-6 shadow-sm">
              <h3 className="text-sm font-bold text-forge-navy uppercase tracking-widest mb-4">Excerpt</h3>
              <textarea 
                value={formData.excerpt} 
                onChange={(e) => setFormData({...formData, excerpt: e.target.value})} 
                rows={4} 
                className="w-full bg-slate-50 border border-slate-200 p-4 text-sm focus:border-forge-gold focus:outline-none"
                placeholder="Write a brief summary for the blog list page..."
              />
            </div>
          </div>

          {/* Sidebar Area (WordPress Right Column) */}
          <div className="w-full lg:w-80 space-y-6">

            {/* Publish Box */}
            <div className="bg-white border border-slate-200 shadow-sm overflow-hidden">
              <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex items-center justify-between">
                <span className="text-[10px] font-bold uppercase tracking-widest text-slate-500">Publish</span>
                <Settings size={14} className="text-slate-400" />
              </div>
              <div className="p-4 space-y-4">
                <div className="text-xs text-slate-600 space-y-2">
                  <div className="flex items-center gap-2">
                    <Globe size={14} /> Status: <span className="font-bold text-forge-navy">{formData.status}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <FileText size={14} /> Visibility: <span className="font-bold text-forge-navy">Public</span>
                  </div>
                </div>
                <div className="flex gap-2 pt-2">
                  <button 
                    type="button" 
                    onClick={(e) => handleSave(e, 'Draft')}
                    disabled={isSubmitting || isSuccess}
                    className="flex-1 py-2 bg-slate-100 text-slate-600 text-[10px] font-bold uppercase tracking-widest hover:bg-slate-200 transition-colors"
                  >
                    Save Draft
                  </button>
                  <button 
                    type="button"
                    className="flex-1 py-2 border border-slate-200 text-slate-500 text-[10px] font-bold uppercase tracking-widest hover:bg-slate-50"
                  >
                    Preview
                  </button>
                </div>
              </div>
              <div className="bg-slate-50 p-4 border-t border-slate-200 flex justify-end">
                <button 
                  type="submit" 
                  onClick={(e) => handleSave(e, 'Published')}
                  disabled={isSubmitting || isSuccess}
                  className="bg-forge-navy text-white px-6 py-2.5 text-[10px] font-bold uppercase tracking-widest hover:bg-forge-dark transition-all flex items-center gap-2 shadow-md"
                >
                  {isSubmitting ? <Loader2 size={12} className="animate-spin" /> : (isSuccess ? <CheckCircle size={12} /> : null)}
                  {isEditing ? 'Update Post' : 'Publish Post'}
                </button>
              </div>
            </div>

            {/* SEO Settings (WordPress Focus Keyphrase / Meta) */}
            <div className="bg-white border border-slate-200 shadow-sm overflow-hidden">
              <div className="bg-slate-50 px-4 py-3 border-b border-slate-200">
                <span className="text-[10px] font-bold uppercase tracking-widest text-slate-500">SEO Settings</span>
              </div>
              <div className="p-4 space-y-4">
                <div>
                  <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Focus Keyphrase</label>
                  <input 
                    type="text" 
                    value={formData.keyphrase || ''} 
                    onChange={(e) => setFormData({...formData, keyphrase: e.target.value})}
                    className="w-full border border-slate-200 p-2 text-sm focus:border-forge-gold focus:outline-none"
                    placeholder="e.g. Luxury Real Estate Lagos"
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Meta Description</label>
                  <textarea 
                    value={formData.meta_description || ''} 
                    onChange={(e) => setFormData({...formData, meta_description: e.target.value})}
                    rows={3}
                    className="w-full border border-slate-200 p-2 text-xs focus:border-forge-gold focus:outline-none resize-none"
                    placeholder="Snippet for search results..."
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">URL Slug</label>
                  <div className="flex items-center gap-1 text-[10px] text-slate-400 bg-slate-50 p-2 border border-slate-100 rounded font-mono">
                    <LinkIcon size={10} /> /{formData.slug}
                  </div>
                </div>
              </div>
            </div>

            {/* Categories Box */}
            <div className="bg-white border border-slate-200 shadow-sm overflow-hidden">
              <div className="bg-slate-50 px-4 py-3 border-b border-slate-200">
                <span className="text-[10px] font-bold uppercase tracking-widest text-slate-500">Categories</span>
              </div>
              <div className="p-4">
                <select 
                  value={formData.category} 
                  onChange={(e) => setFormData({...formData, category: e.target.value})}
                  className="w-full border border-slate-200 p-2 text-sm focus:outline-none"
                >
                  {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </div>
            </div>

            {/* Featured Image Box */}
            <div className="bg-white border border-slate-200 shadow-sm overflow-hidden">
              <div className="bg-slate-50 px-4 py-3 border-b border-slate-200">
                <span className="text-[10px] font-bold uppercase tracking-widest text-slate-500">Featured Image</span>
              </div>
              <div className="p-4">
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="aspect-video bg-slate-50 border-2 border-dashed border-slate-200 rounded flex flex-col items-center justify-center cursor-pointer hover:border-forge-gold overflow-hidden relative group"
                >
                  {formData.cover_image ? (
                    <>
                      <img src={formData.cover_image} className="w-full h-full object-cover" />
                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center text-white text-[10px] font-bold">Change Image</div>
                    </>
                  ) : (
                    <div className="flex flex-col items-center">
                      {isUploading ? <Loader2 size={20} className="animate-spin text-forge-gold" /> : <ImageIcon size={20} className="text-slate-300" />}
                      <span className="text-[8px] text-slate-400 font-bold uppercase mt-2">Set Featured Image</span>
                    </div>
                  )}
                </div>
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleCoverUpload} />
              </div>
            </div>

          </div>
        </form>
      </div>
    </AdminLayout>
  );
};

import React from 'react';
import { DollarSign, Home, Users, TrendingUp, Activity, MapPin } from 'lucide-react';
import { useProperties } from '../context/PropertyContext';
import { AdminLayout } from '../components/AdminLayout';

export const AdminAnalytics: React.FC = () => {
  const { properties, leads } = useProperties();

  // STRICT FILTERING: Exclude any artifacts, mock data, or entries without names/emails
  const validLeads = leads.filter(l => 
    l && 
    l.name && 
    l.name.trim() !== '' && 
    l.name !== 'Chief Adewale' && 
    l.email !== 'test@example.com' &&
    l.email.includes('@')
  );

  // Metrics derived ONLY from validLeads array
  const totalValue = properties.reduce((sum, p) => sum + (p.price || 0), 0);
  const activeListings = properties.filter(p => p.status === 'For Sale' || p.status === 'For Rent').length;
  const soldListings = properties.filter(p => p.status === 'Sold').length;

  // These counts will accurately reflect 0 if validLeads is empty
  const totalLeadsCount = validLeads.length;
  const newLeads = validLeads.filter(l => l.status === 'New').length;
  const closedLeads = validLeads.filter(l => l.status === 'Closed').length;

  const conversionRate = totalLeadsCount > 0 ? (closedLeads / totalLeadsCount) * 100 : 0;

  const locationStats = properties.reduce((acc: Record<string, number>, curr) => {
    const city = (curr.location || 'Unknown').split(',')[0].trim();
    acc[city] = (acc[city] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const totalProps = properties.length;
  const sortedLocations = Object.entries(locationStats)
    .sort((a, b) => (b[1] as number) - (a[1] as number))
    .slice(0, 5)
    .map(([loc, count]) => ({
      loc,
      count: count as number,
      percent: totalProps > 0 ? Math.round(((count as number) / totalProps) * 100) : 0
    }));

  const colors = ['bg-forge-navy', 'bg-forge-gold', 'bg-slate-400', 'bg-blue-500', 'bg-green-500'];

  const activityLog = [
    ...validLeads.map(l => ({
      type: 'lead',
      date: new Date(l.date).getTime(),
      user: 'System',
      action: `New ${l.type.toLowerCase()}`,
      target: l.name,
      displayTime: l.date
    })),
    ...properties.map(p => {
      let date = Date.now();
      if (p.id.length > 10 && !isNaN(Number(p.id))) {
        date = Number(p.id);
      } 
      return {
        type: 'property',
        date,
        user: 'Admin',
        action: 'Property listed',
        target: p.title,
        displayTime: new Date(date).toLocaleDateString()
      };
    })
  ].sort((a, b) => b.date - a.date).slice(0, 8);

  return (
    <AdminLayout>
      <div className="max-w-6xl">
        <h1 className="text-3xl font-serif text-forge-navy mb-8">Performance Analytics</h1>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-12">
          <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
            <div className="flex items-center gap-4 mb-2">
              <div className="p-3 bg-green-50 text-green-600 rounded-full"><DollarSign size={20} /></div>
              <span className="text-slate-500 text-[10px] font-bold uppercase tracking-widest">Portfolio Value</span>
            </div>
            <h3 className="text-2xl font-bold text-forge-navy truncate">₦{(totalValue / 1000000000).toFixed(2)}B</h3>
            <p className="text-xs text-green-600 mt-1 flex items-center gap-1"><TrendingUp size={12} /> Live Valuation</p>
          </div>

          <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
            <div className="flex items-center gap-4 mb-2">
              <div className="p-3 bg-blue-50 text-blue-600 rounded-full"><Home size={20} /></div>
              <span className="text-slate-500 text-[10px] font-bold uppercase tracking-widest">Active Listings</span>
            </div>
            <h3 className="text-2xl font-bold text-forge-navy">{activeListings}</h3>
            <p className="text-xs text-slate-400 mt-1">{soldListings} properties sold</p>
          </div>

          <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
            <div className="flex items-center gap-4 mb-2">
              <div className="p-3 bg-orange-50 text-orange-600 rounded-full"><Users size={20} /></div>
              <span className="text-slate-500 text-[10px] font-bold uppercase tracking-widest">Total Leads</span>
            </div>
            <h3 className="text-2xl font-bold text-forge-navy">{totalLeadsCount}</h3>
            <p className="text-xs text-orange-600 mt-1">{newLeads} new (pending)</p>
          </div>

          <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
             <div className="flex items-center gap-4 mb-2">
              <div className="p-3 bg-purple-50 text-purple-600 rounded-full"><TrendingUp size={20} /></div>
              <span className="text-slate-500 text-[10px] font-bold uppercase tracking-widest">Conversion Rate</span>
            </div>
            <h3 className="text-2xl font-bold text-forge-navy">
              {conversionRate.toFixed(1)}%
            </h3>
            <p className="text-xs text-slate-400 mt-1">{closedLeads} leads closed</p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
           <div className="bg-white p-8 rounded-lg shadow-sm border border-slate-200">
             <div className="flex items-center justify-between mb-6">
                <h3 className="font-serif text-lg text-forge-navy">Inventory by Location</h3>
                <MapPin size={18} className="text-slate-400" />
             </div>

             {sortedLocations.length > 0 ? (
               <div className="space-y-4">
                 {sortedLocations.map((item, i) => (
                   <div key={i}>
                      <div className="flex justify-between text-sm mb-1">
                        <span className="font-bold text-slate-600">{item.loc}</span>
                        <span className="text-slate-400">{item.percent}% ({item.count})</span>
                      </div>
                      <div className="w-full bg-slate-100 rounded-full h-2">
                        <div className={`h-2 rounded-full ${colors[i % colors.length]}`} style={{ width: `${item.percent}%` }}></div>
                      </div>
                   </div>
                 ))}
               </div>
             ) : (
               <div className="text-center text-slate-400 py-12">No inventory data available.</div>
             )}
           </div>

           <div className="bg-white p-8 rounded-lg shadow-sm border border-slate-200">
             <div className="flex items-center justify-between mb-6">
               <h3 className="font-serif text-lg text-forge-navy">Recent Activity Log</h3>
               <Activity size={18} className="text-slate-400" />
             </div>

             {activityLog.length > 0 ? (
               <div className="space-y-6">
                  {activityLog.map((log, i) => (
                    <div key={i} className="flex gap-4 items-start border-b border-slate-50 pb-4 last:border-0 last:pb-0">
                      <div className={`w-2 h-2 mt-2 rounded-full shrink-0 ${log.type === 'lead' ? 'bg-orange-400' : 'bg-forge-gold'}`}></div>
                      <div>
                        <p className="text-sm font-bold text-forge-navy">{log.action}</p>
                        <p className="text-xs text-slate-500">
                          {log.target} • <span className="text-slate-400">{log.displayTime}</span>
                        </p>
                      </div>
                    </div>
                  ))}
               </div>
             ) : (
               <div className="text-center text-slate-400 py-12">No recent activity.</div>
             )}
           </div>
        </div>
      </div>
    </AdminLayout>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { 
  ArrowLeft, CheckCircle, Image as ImageIcon, Loader2, Link as LinkIcon, 
  AlertCircle, Globe, Settings, FileText
} from 'lucide-react';
import { useProperties } from '../context/PropertyContext';
import { BlogPost } from '../types';
import { AdminLayout } from '../components/AdminLayout';
import { RichTextEditor } from '../components/RichTextEditor';
import { resizeImage, dataURLtoBlob } from '../utils/imageUtils';
import { uploadImage } from '../lib/supabaseClient';

export const AdminPostForm: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { getPost, addPost, updatePost, isLoading } = useProperties();
  const isEditing = !!id;

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState('');
  const [dataLoaded, setDataLoaded] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [categories] = useState(['Market Insights', 'Luxury Lifestyle', 'Company News', 'Investment']);

  const [formData, setFormData] = useState<BlogPost>({
    id: '',
    slug: '',
    title: '',
    excerpt: '',
    content: '',
    cover_image: '',
    author: 'The Forge Properties',
    date: new Date().toISOString(),
    category: 'Market Insights',
    status: 'Draft',
    meta_description: '',
    keyphrase: ''
  });

  const slugify = (text: string) => {
    return text.toString().toLowerCase().trim()
      .replace(/\s+/g, '-')
      .replace(/[^\w-]+/g, '')
      .replace(/--+/g, '-')
      .replace(/^-+/, '')
      .replace(/-+$/, '');
  };

  useEffect(() => {
    if (!isLoading) {
      if (isEditing && id) {
        const post = getPost(id);
        if (post) {
          setFormData(post);
          setDataLoaded(true);
        } else {
          setError("Post not found.");
        }
      } else {
        setFormData({
          id: Date.now().toString(), slug: '', title: '', excerpt: '', content: '',
          cover_image: '', author: 'The Forge Properties', date: new Date().toISOString(),
          category: 'Market Insights', status: 'Draft', meta_description: '', keyphrase: ''
        });
        setDataLoaded(true);
      }
    }
  }, [id, isEditing, getPost, isLoading]);

  const handleTitleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newTitle = e.target.value;
    setFormData(prev => ({
      ...prev,
      title: newTitle,
      slug: (!prev.slug || prev.slug === slugify(prev.title)) ? slugify(newTitle) : prev.slug
    }));
  };

  const handleCoverUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    setError('');
    try {
      const resizedBase64 = await resizeImage(file, 1200, 630);
      const blob = dataURLtoBlob(resizedBase64);
      const fileName = `blog-${Date.now()}-${file.name.replace(/[^a-zA-Z0-9.]/g, '_')}`;
      const publicUrl = await uploadImage('blog-images', fileName, blob);
      setFormData({ ...formData, cover_image: publicUrl });
    } catch (err: any) {
      setError(`Upload failed: ${err.message}. If permissions persist, run the RLS SQL fix.`);
    } finally {
      setIsUploading(false);
    }
  };

  const handleSave = async (e: React.FormEvent, statusOverride?: 'Published' | 'Draft') => {
    e.preventDefault();
    if (!formData.title.trim()) {
      setError("Article title is required.");
      return;
    }

    setIsSubmitting(true);
    setError('');

    const submissionData = { 
      ...formData, 
      status: statusOverride || formData.status,
      slug: formData.slug || slugify(formData.title)
    };

    try {
      if (isEditing) await updatePost(submissionData);
      else await addPost(submissionData);
      setIsSuccess(true);
      setTimeout(() => navigate('/admin/blog'), 1200);
    } catch (err: any) {
      setError(err.message || "Failed to save post.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isLoading || (isEditing && !dataLoaded)) {
    return (
      <AdminLayout>
        <div className="flex flex-col items-center justify-center min-h-[50vh]">
          <Loader2 size={32} className="animate-spin text-forge-gold mb-4" />
          <p className="font-serif italic text-slate-400">Loading Article...</p>
        </div>
      </AdminLayout>
    );
  }

  return (
    <AdminLayout>
      <div className="max-w-[1400px] mx-auto pb-20">
        <div className="flex items-center justify-between mb-6">
          <h1 className="text-2xl font-serif font-bold text-forge-navy">
            {isEditing ? 'Edit Post' : 'Add New Post'}
          </h1>
          <button onClick={() => navigate('/admin/blog')} className="text-slate-400 hover:text-forge-navy flex items-center gap-2 text-xs font-bold uppercase tracking-widest">
            <ArrowLeft size={14} /> Back to Blog List
          </button>
        </div>

        {error && (
          <div className="bg-red-50 text-red-700 p-4 rounded mb-6 text-sm border border-red-200 flex items-center gap-2">
            <AlertCircle size={16} /> {error}
          </div>
        )}

        <form onSubmit={(e) => handleSave(e)} className="flex flex-col lg:flex-row gap-8">
          {/* Main Content Area (WordPress Left Column) */}
          <div className="flex-1 space-y-6">
            <input 
              type="text" 
              value={formData.title} 
              onChange={handleTitleChange} 
              placeholder="Enter title here"
              className="w-full bg-white border border-slate-200 p-4 text-2xl font-serif font-bold focus:border-forge-gold focus:outline-none shadow-sm"
              required
            />

            <div className="bg-white border border-slate-200 shadow-sm">
              <RichTextEditor value={formData.content} onChange={(content) => setFormData({...formData, content})} />
            </div>

            <div className="bg-white border border-slate-200 p-6 shadow-sm">
              <h3 className="text-sm font-bold text-forge-navy uppercase tracking-widest mb-4">Excerpt</h3>
              <textarea 
                value={formData.excerpt} 
                onChange={(e) => setFormData({...formData, excerpt: e.target.value})} 
                rows={4} 
                className="w-full bg-slate-50 border border-slate-200 p-4 text-sm focus:border-forge-gold focus:outline-none"
                placeholder="Write a brief summary for the blog list page..."
              />
            </div>
          </div>

          {/* Sidebar Area (WordPress Right Column) */}
          <div className="w-full lg:w-80 space-y-6">

            {/* Publish Box */}
            <div className="bg-white border border-slate-200 shadow-sm overflow-hidden">
              <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex items-center justify-between">
                <span className="text-[10px] font-bold uppercase tracking-widest text-slate-500">Publish</span>
                <Settings size={14} className="text-slate-400" />
              </div>
