import React, { useRef, useEffect, useState } from 'react';
import { 
  Bold, Italic, List, ListOrdered, AlignLeft, AlignCenter, AlignRight, 
  Undo, Redo, Code, Link as LinkIcon, Quote
} from 'lucide-react';

interface RichTextEditorProps {
  value: string;
  onChange: (value: string) => void;
}

export const RichTextEditor: React.FC<RichTextEditorProps> = ({ value, onChange }) => {
  const editorRef = useRef<HTMLDivElement>(null);
  const isInternalChange = useRef(false);
  const [isCodeView, setIsCodeView] = useState(false);
  const [currentBlock, setCurrentBlock] = useState('P');

  // Sync initial value or external updates to editor content
  useEffect(() => {
    if (editorRef.current && !isInternalChange.current && !isCodeView && editorRef.current.innerHTML !== value) {
      editorRef.current.innerHTML = value || '<p><br></p>';
    }
  }, [value, isCodeView]);

  const handleInput = () => {
    if (editorRef.current) {
      isInternalChange.current = true;
      onChange(editorRef.current.innerHTML);
      setTimeout(() => isInternalChange.current = false, 0);
    }
  };

  const execCommand = (command: string, ui: boolean = false, val: string | undefined = undefined) => {
    if (isCodeView) return;

    // Ensure editor is focused before executing command
    editorRef.current?.focus();

    try {
      // Use execCommand - note: standard identifiers for formatBlock are H1, H2, etc.
      document.execCommand(command, ui, val);
    } catch (e) {
      console.warn('ExecCommand failed:', e);
    }
    handleInput();
  };

  const handleBlockChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const val = e.target.value;
    setCurrentBlock(val);
    // Standard formatBlock command values (H1, H2, H3, etc.)
    execCommand('formatBlock', false, val);
  };

  const insertLink = () => {
    const url = prompt("Enter the URL:");
    if (url) {
      execCommand('createLink', false, url);
    }
  };

  const toggleCodeView = () => {
    setIsCodeView(!isCodeView);
  };

  const ToolbarButton = ({ 
    icon: Icon, 
    onClick,
    title,
    disabled = false,
    active = false
  }: { 
    icon: any, 
    onClick: () => void, 
    title: string,
    disabled?: boolean,
    active?: boolean
  }) => (
    <button
      type="button"
      onClick={onClick}
      disabled={disabled}
      className={`p-2 rounded transition-colors ${
        active ? 'bg-forge-gold text-forge-navy' : 
        disabled ? 'text-slate-300 cursor-not-allowed' : 
        'text-slate-600 hover:text-forge-navy hover:bg-slate-100'
      }`}
      title={title}
    >
      <Icon size={18} />
    </button>
  );

  return (
    <div className="border border-slate-200 rounded-sm overflow-hidden bg-white flex flex-col h-[600px] shadow-sm">
      {/* Toolbar */}
      <div className="flex flex-wrap items-center gap-1 p-2 bg-slate-50 border-b border-slate-200">

        {/* 1. Headings Dropdown (P, H1-H6) */}
        <div className="flex items-center border-r border-slate-200 pr-2 mr-1">
          <select 
            value={currentBlock}
            onChange={handleBlockChange}
            disabled={isCodeView}
            className="bg-transparent text-sm font-bold text-slate-700 focus:outline-none cursor-pointer py-1 max-w-[140px] ml-1"
          >
            <option value="P">Paragraph</option>
            <option value="H1">Heading 1</option>
            <option value="H2">Heading 2</option>
            <option value="H3">Heading 3</option>
            <option value="H4">Heading 4</option>
            <option value="H5">Heading 5</option>
            <option value="H6">Heading 6</option>
            <option value="PRE">Preformatted</option>
          </select>
        </div>

        {/* 2. Standard Formatting */}
        <div className="flex items-center gap-1 border-r border-slate-200 pr-2 mr-1">
          <ToolbarButton icon={Bold} onClick={() => execCommand('bold')} title="Bold" disabled={isCodeView} />
          <ToolbarButton icon={Italic} onClick={() => execCommand('italic')} title="Italic" disabled={isCodeView} />
          <ToolbarButton icon={LinkIcon} onClick={insertLink} title="Insert Link" disabled={isCodeView} />
        </div>

        {/* 3. Alignment */}
        <div className="flex items-center gap-1 border-r border-slate-200 pr-2 mr-1">
          <ToolbarButton icon={AlignLeft} onClick={() => execCommand('justifyLeft')} title="Align Left" disabled={isCodeView} />
          <ToolbarButton icon={AlignCenter} onClick={() => execCommand('justifyCenter')} title="Align Center" disabled={isCodeView} />
          <ToolbarButton icon={AlignRight} onClick={() => execCommand('justifyRight')} title="Align Right" disabled={isCodeView} />
        </div>

        {/* 4. Lists & Quote Group (Bullet, Numbered, Quote) */}
        <div className="flex items-center gap-1 border-r border-slate-200 pr-2 mr-1">
           <ToolbarButton icon={List} onClick={() => execCommand('insertUnorderedList')} title="Bullet List" disabled={isCodeView} />
           <ToolbarButton icon={ListOrdered} onClick={() => execCommand('insertOrderedList')} title="Numbered List" disabled={isCodeView} />
           <ToolbarButton icon={Quote} onClick={() => execCommand('formatBlock', false, 'BLOCKQUOTE')} title="Blockquote" disabled={isCodeView} />
        </div>

        {/* 5. Undo/Redo */}
        <div className="flex items-center gap-1">
          <ToolbarButton icon={Undo} onClick={() => execCommand('undo')} title="Undo" disabled={isCodeView} />
          <ToolbarButton icon={Redo} onClick={() => execCommand('redo')} title="Redo" disabled={isCodeView} />
        </div>

        {/* 6. Code View Toggle */}
        <div className="ml-auto flex items-center border-l border-slate-200 pl-2">
            <button
              type="button"
              onClick={toggleCodeView}
              className={`flex items-center gap-2 px-3 py-1.5 rounded text-xs font-bold uppercase tracking-wider transition-colors ${
                isCodeView 
                  ? 'bg-forge-navy text-white' 
                  : 'text-slate-500 hover:bg-slate-200'
              }`}
            >
              <Code size={14} />
              {isCodeView ? 'Visual' : 'Code'}
            </button>
        </div>
      </div>

      {/* Editor Area */}
      {isCodeView ? (
        <textarea
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="flex-grow p-6 w-full h-full bg-slate-900 text-green-400 font-mono text-sm leading-relaxed focus:outline-none resize-none"
          spellCheck={false}
        />
      ) : (
        <div 
          ref={editorRef}
          className="flex-grow p-8 overflow-y-auto focus:outline-none article-content"
          contentEditable
          onInput={handleInput}
          spellCheck={true}
          style={{ minHeight: '400px' }}
        />
      )}

      <div className="bg-slate-50 border-t border-slate-100 p-2 text-[10px] text-slate-400 uppercase tracking-wider font-bold text-right px-4 flex justify-between items-center">
        <span>{isCodeView ? 'HTML SOURCE MODE' : 'VISUAL EDITOR MODE'}</span>
        <span>{value.length} Characters</span>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { 
  ArrowLeft, CheckCircle, Image as ImageIcon, Loader2, Link as LinkIcon, 
  AlertCircle, Globe, Settings, FileText, ChevronDown, Calendar, Plus
} from 'lucide-react';
import { useProperties } from '../context/PropertyContext';
import { BlogPost } from '../types';
import { AdminLayout } from '../components/AdminLayout';
import { RichTextEditor } from '../components/RichTextEditor';
import { resizeImage, dataURLtoBlob } from '../utils/imageUtils';
import { uploadImage } from '../lib/supabaseClient';

export const AdminPostForm: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { posts, getPost, addPost, updatePost, isLoading } = useProperties();
  const isEditing = !!id;

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState('');
  const [dataLoaded, setDataLoaded] = useState(false);
  const [isEditingSlug, setIsEditingSlug] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Local state for categories added during this specific form session
  const [sessionCategories, setSessionCategories] = useState<string[]>([]);
  const [isAddingCategory, setIsAddingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');

  const [formData, setFormData] = useState<BlogPost>({
    id: '',
    slug: '',
    title: '',
    excerpt: '',
    content: '',
    cover_image: '',
    author: 'The Forge Properties',
    date: new Date().toISOString(),
    category: 'Market Insights',
    status: 'Draft',
    meta_description: '',
    keyphrase: ''
  });

  // Dynamically derive all available categories from defaults, existing posts, and current session additions
  const availableCategories = useMemo(() => {
    const defaults = ['Market Insights', 'Luxury Lifestyle', 'Company News', 'Investment'];
    const fromPosts = posts.map(p => p.category).filter(Boolean);
    const combined = Array.from(new Set([...defaults, ...fromPosts, ...sessionCategories]));
    return combined.sort();
  }, [posts, sessionCategories]);

  const slugify = (text: string) => {
    return text.toString().toLowerCase().trim()
      .replace(/\s+/g, '-')
      .replace(/[^\w-]+/g, '')
      .replace(/--+/g, '-')
      .replace(/^-+/, '')
      .replace(/-+$/, '');
  };

  useEffect(() => {
    if (!isLoading) {
      if (isEditing && id) {
        const post = getPost(id);
        if (post) {
          setFormData(post);
          setDataLoaded(true);
        } else {
          setError("Post not found.");
        }
      } else {
        setFormData({
          id: Date.now().toString(), slug: '', title: '', excerpt: '', content: '',
          cover_image: '', author: 'The Forge Properties', date: new Date().toISOString(),
          category: 'Market Insights', status: 'Draft', meta_description: '', keyphrase: ''
        });
        setDataLoaded(true);
      }
    }
  }, [id, isEditing, getPost, isLoading]);

  const handleTitleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newTitle = e.target.value;
    setFormData(prev => ({
      ...prev,
      title: newTitle,
      slug: (!prev.slug || prev.slug === slugify(prev.title)) ? slugify(newTitle) : prev.slug
    }));
  };

  const handleCoverUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    setError('');
    try {
      const resizedBase64 = await resizeImage(file, 1200, 630);
      const blob = dataURLtoBlob(resizedBase64);
      const fileName = `blog-${Date.now()}-${file.name.replace(/[^a-zA-Z0-9.]/g, '_')}`;
      const publicUrl = await uploadImage('blog-images', fileName, blob);
      setFormData({ ...formData, cover_image: publicUrl });
    } catch (err: any) {
      setError(`Upload failed: ${err.message}.`);
    } finally {
      setIsUploading(false);
    }
  };

  const handleAddCategory = () => {
    const trimmed = newCategoryName.trim();
    if (trimmed) {
      // Add to session categories so it appears in the list immediately
      if (!availableCategories.includes(trimmed)) {
        setSessionCategories(prev => [...prev, trimmed]);
      }
      // Update the actual form data with the new category
      setFormData(prev => ({ ...prev, category: trimmed }));
      setNewCategoryName('');
      setIsAddingCategory(false);
    }
  };

  const handleSave = async (e: React.FormEvent, statusOverride?: 'Published' | 'Draft') => {
    e.preventDefault();
    if (!formData.title.trim()) {
      setError("Article title is required.");
      return;
    }

    setIsSubmitting(true);
    setError('');

    // Ensure we are saving exactly what's in the formData
    const submissionData = { 
      ...formData, 
      status: statusOverride || formData.status,
      slug: formData.slug || slugify(formData.title)
    };

    try {
      if (isEditing) await updatePost(submissionData);
      else await addPost(submissionData);
      setIsSuccess(true);
      setTimeout(() => navigate('/admin/blog'), 1200);
    } catch (err: any) {
      setError(err.message || "Failed to save post.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isLoading || (isEditing && !dataLoaded)) {
    return (
      <AdminLayout>
        <div className="flex flex-col items-center justify-center min-h-[50vh]">
          <Loader2 size={32} className="animate-spin text-forge-gold mb-4" />
          <p className="font-serif italic text-slate-400">Loading Article...</p>
        </div>
      </AdminLayout>
    );
  }

  return (
    <AdminLayout>
      <div className="max-w-[1400px] mx-auto pb-20">
        <div className="flex items-center gap-4 mb-6">
          <h1 className="text-2xl font-sans font-normal text-slate-800">
            {isEditing ? 'Edit Post' : 'Add New Post'}
          </h1>
          <button type="button" onClick={() => navigate('/admin/blog/new')} className="px-2 py-1 border border-slate-300 rounded bg-white text-blue-600 text-xs font-bold hover:bg-blue-600 hover:text-white transition-colors">
            Add New
          </button>
        </div>

        {error && (
          <div className="bg-red-50 text-red-700 p-4 rounded mb-6 text-sm border border-red-200 flex items-center gap-2">
            <AlertCircle size={16} /> {error}
          </div>
        )}

        <form onSubmit={(e) => handleSave(e)} className="flex flex-col lg:flex-row gap-6">

          {/* Main Column (Left) */}
          <div className="flex-1 space-y-4">
            {/* 1. Title */}
            <input 
              type="text" 
              value={formData.title} 
              onChange={handleTitleChange} 
              placeholder="Enter title here"
              className="w-full bg-white border border-slate-300 p-2 text-xl focus:border-blue-400 focus:outline-none"
              required
            />

            {/* 2. Permalink (URL Slug) */}
            <div className="text-sm flex items-center gap-1 text-slate-600">
              <span className="font-bold">Permalink:</span>
              <span>https://theforgeproperties.com/blog/</span>
              {isEditingSlug ? (
                <div className="flex items-center gap-2">
                  <input 
                    type="text" 
                    value={formData.slug} 
                    onChange={(e) => setFormData({...formData, slug: slugify(e.target.value)})}
                    className="border border-slate-300 px-1 text-xs"
                  />
                  <button type="button" onClick={() => setIsEditingSlug(false)} className="px-2 py-0.5 bg-slate-100 border border-slate-300 text-[10px] rounded">OK</button>
                </div>
              ) : (
                <div className="flex items-center gap-2">
                  <span className="bg-yellow-50 px-1">{formData.slug || '(slug)'}</span>
                  <button type="button" onClick={() => setIsEditingSlug(true)} className="px-2 py-0.5 bg-white border border-slate-300 text-[10px] rounded hover:bg-slate-50">Edit</button>
                </div>
              )}
            </div>

            {/* 3. Content Editor */}
            <div className="bg-white border border-slate-300">
              <RichTextEditor value={formData.content} onChange={(content) => setFormData({...formData, content})} />
            </div>

            {/* 4. Excerpt Box */}
            <div className="bg-white border border-slate-300 overflow-hidden shadow-sm">
              <div className="bg-slate-50 px-3 py-2 border-b border-slate-300 flex justify-between items-center cursor-default">
                <span className="text-sm font-bold text-slate-700">Excerpt</span>
                <ChevronDown size={14} className="text-slate-400" />
              </div>
              <div className="p-4">
                <textarea 
                  value={formData.excerpt} 
                  onChange={(e) => setFormData({...formData, excerpt: e.target.value})} 
                  rows={3} 
                  className="w-full border border-slate-300 p-2 text-sm focus:outline-none focus:border-blue-300"
                  placeholder="Excerpts are optional hand-crafted summaries of your content..."
                />
              </div>
            </div>

            {/* 5. SEO Focus Keyphrase */}
