import React, { createContext, useState, useContext, ReactNode, useEffect } from 'react';
import { Property, Lead, SiteSettings, Subscriber, BlogPost, BlogCategory } from '../types';
import { supabase } from '../lib/supabaseClient';

interface PropertyContextType {
  properties: Property[];
  leads: Lead[];
  subscribers: Subscriber[];
  posts: BlogPost[];
  categories: BlogCategory[];
  settings: SiteSettings;
  isLoading: boolean;
  addProperty: (property: Property) => Promise<void>;
  updateProperty: (property: Property) => Promise<void>;
  deleteProperty: (id: string) => Promise<void>;
  getProperty: (id: string) => Property | undefined;
  getPropertyBySlug: (slug: string) => Property | undefined;
  addLead: (lead: Lead) => Promise<void>;
  updateLeadStatus: (id: string, status: Lead['status']) => Promise<void>;
  addSubscriber: (email: string) => Promise<void>;
  updateSettings: (settings: SiteSettings) => Promise<void>;
  addPost: (post: BlogPost) => Promise<void>;
  updatePost: (post: BlogPost) => Promise<void>;
  deletePost: (id: string) => Promise<void>;
  getPost: (id: string) => BlogPost | undefined;
  getPostBySlug: (slug: string) => BlogPost | undefined;
  addCategory: (name: string) => Promise<BlogCategory>;
  seedDatabase: () => Promise<void>;
}

const PropertyContext = createContext<PropertyContextType | undefined>(undefined);

const DEFAULT_SETTINGS: SiteSettings = {
  contact_email: 'theforgeproperties@gmail.com',
  contact_phone: '+234 800 FORGE 00',
  address: 'Silverland Estate, Sangotedo, Ajah, Lagos, Nigeria',
  team_members: [
    { name: "Daniel Paul", role: "Co-Founder", image: "" },
    { name: "Paul Bolaji", role: "Co-Founder", image: "" },
    { name: "Samuel Oshin", role: "Co-Founder", image: "" }
  ],
  listing_agent: {
    name: "The Forge Properties",
    phone: "+234 800 FORGE 00",
    image: "https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?q=80&w=200"
  }
};

export const PropertyProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [properties, setProperties] = useState<Property[]>([]);
  const [leads, setLeads] = useState<Lead[]>([]);
  const [subscribers, setSubscribers] = useState<Subscriber[]>([]);
  const [posts, setPosts] = useState<BlogPost[]>([]);
  const [categories, setCategories] = useState<BlogCategory[]>([]);
  const [settings, setSettings] = useState<SiteSettings>(DEFAULT_SETTINGS);
  const [isLoading, setIsLoading] = useState(true);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data: propsData } = await supabase.from('properties').select('*').order('id', { ascending: false });
      if (propsData) setProperties(propsData);

      const { data: leadsData } = await supabase.from('leads').select('*').order('date', { ascending: false });
      if (leadsData) setLeads(leadsData);

      const { data: subsData } = await supabase.from('subscribers').select('*');
      if (subsData) setSubscribers(subsData);

      const { data: postsData } = await supabase.from('posts').select('*').order('date', { ascending: false });
      if (postsData) setPosts(postsData);

      const { data: catsData } = await supabase.from('blog_categories').select('*').order('name', { ascending: true });
      if (catsData) setCategories(catsData);

      const { data: settingsData } = await supabase.from('site_settings').select('*').eq('id', 1).single();
      if (settingsData) {
        setSettings({ ...DEFAULT_SETTINGS, ...settingsData });
      }
    } catch (error) {
      console.error('Fetch error:', error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const addCategory = async (name: string): Promise<BlogCategory> => {
    const slug = name.toLowerCase().trim().replace(/\s+/g, '-').replace(/[^\w-]+/g, '');
    const newCat = { name, slug };

    const { data, error } = await supabase.from('blog_categories').insert([newCat]).select().single();

    if (error) throw error;
    setCategories(prev => [...prev, data].sort((a, b) => a.name.localeCompare(b.name)));
    return data;
  };

  const seedDatabase = async () => {
    setIsLoading(true);
    try {
      const { data: existingSettings } = await supabase.from('site_settings').select('*').eq('id', 1).single();
      if (!existingSettings) {
        await supabase.from('site_settings').upsert({ id: 1, ...DEFAULT_SETTINGS });
      }
      await fetchData();
      alert("System configuration initialized.");
    } catch (err) {
      console.error(err);
      alert("Initialization failed.");
    } finally {
      setIsLoading(false);
    }
  };

  const addProperty = async (property: Property) => {
    const { error } = await supabase.from('properties').insert([property]);
    if (error) throw error;
    setProperties(prev => [property, ...prev]);
  };

  const updateProperty = async (updatedProperty: Property) => {
    const { error } = await supabase.from('properties').update(updatedProperty).eq('id', updatedProperty.id);
    if (error) throw error;
    setProperties(prev => prev.map(p => p.id === updatedProperty.id ? updatedProperty : p));
  };

  const deleteProperty = async (id: string) => {
    const { error } = await supabase.from('properties').delete().eq('id', id);
    if (error) throw error;
    setProperties(prev => prev.filter(p => p.id !== id));
  };

  const addLead = async (lead: Lead) => {
    const { error } = await supabase.from('leads').insert([lead]);
    if (error) throw error;
    setLeads(prev => [lead, ...prev]);
  };

  const updateLeadStatus = async (id: string, status: Lead['status']) => {
    const { error } = await supabase.from('leads').update({ status }).eq('id', id);
    if (error) throw error;
    setLeads(prev => prev.map(l => l.id === id ? { ...l, status } : l));
  };

  const addSubscriber = async (email: string) => {
    if (subscribers.some(s => s.email === email)) return;
    const newSubscriber: Subscriber = { id: Date.now().toString(), email, date: new Date().toISOString() };
    const { error } = await supabase.from('subscribers').insert([newSubscriber]);
    if (error) throw error;
    setSubscribers(prev => [newSubscriber, ...prev]);
  };

  const addPost = async (post: BlogPost) => {
    const { error } = await supabase.from('posts').insert([post]);
    if (error) throw error;
    setPosts(prev => [post, ...prev]);
  };

  const updatePost = async (updatedPost: BlogPost) => {
    const { error } = await supabase.from('posts').update(updatedPost).eq('id', updatedPost.id);
    if (error) throw error;
    setPosts(prev => prev.map(p => p.id === updatedPost.id ? updatedPost : p));
  };

  const deletePost = async (id: string) => {
    const { error } = await supabase.from('posts').delete().eq('id', id);
    if (error) throw error;
    setPosts(prev => prev.filter(p => p.id !== id));
  };

  const updateSettings = async (newSettings: SiteSettings) => {
    const { error } = await supabase.from('site_settings').update(newSettings).eq('id', 1);
    if (error) throw error;
    setSettings(newSettings);
  };

  return (
    <PropertyContext.Provider value={{ 
      properties, leads, subscribers, posts, categories, settings, isLoading,
      addProperty, updateProperty, deleteProperty, getProperty: (id) => properties.find(p => p.id === id), getPropertyBySlug: (slug) => properties.find(p => p.slug === slug),
      addLead, updateLeadStatus, addSubscriber, updateSettings,
      addPost, updatePost, deletePost, getPost: (id) => posts.find(p => p.id === id), getPostBySlug: (slug) => posts.find(p => p.slug === slug),
      addCategory,
      seedDatabase
    }}>
      {children}
    </PropertyContext.Provider>
  );
};

export const useProperties = () => {
  const context = useContext(PropertyContext);
  if (!context) throw new Error('useProperties must be used within a PropertyProvider');
  return context;
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { 
  Loader2, AlertCircle, ChevronDown, Calendar
} from 'lucide-react';
import { useProperties } from '../context/PropertyContext';
import { BlogPost } from '../types';
import { AdminLayout } from '../components/AdminLayout';
import { RichTextEditor } from '../components/RichTextEditor';
import { resizeImage, dataURLtoBlob } from '../utils/imageUtils';
import { uploadImage } from '../lib/supabaseClient';

export const AdminPostForm: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { categories, getPost, addPost, updatePost, addCategory, isLoading } = useProperties();
  const isEditing = !!id;

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState('');
  const [dataLoaded, setDataLoaded] = useState(false);
  const [isEditingSlug, setIsEditingSlug] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isAddingCategory, setIsAddingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');

  const [formData, setFormData] = useState<BlogPost>({
    id: '',
    slug: '',
    title: '',
    excerpt: '',
    content: '',
    cover_image: '',
    author: 'The Forge Properties',
    date: new Date().toISOString(),
    category: 'Market Insights',
    status: 'Draft',
    meta_description: '',
    keyphrase: ''
  });

  const slugify = (text: string) => {
    return text.toString().toLowerCase().trim()
      .replace(/\s+/g, '-')
      .replace(/[^\w-]+/g, '')
      .replace(/--+/g, '-')
      .replace(/^-+/, '')
      .replace(/-+$/, '');
  };

  useEffect(() => {
    if (!isLoading) {
      if (isEditing && id) {
        const post = getPost(id);
        if (post) {
          setFormData(post);
          setDataLoaded(true);
        } else {
          setError("Post not found.");
        }
      } else {
        setFormData({
          id: Date.now().toString(), slug: '', title: '', excerpt: '', content: '',
          cover_image: '', author: 'The Forge Properties', date: new Date().toISOString(),
          category: 'Market Insights', status: 'Draft', meta_description: '', keyphrase: ''
        });
        setDataLoaded(true);
      }
    }
  }, [id, isEditing, getPost, isLoading]);

  const handleTitleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newTitle = e.target.value;
    setFormData(prev => ({
      ...prev,
      title: newTitle,
      slug: (!prev.slug || prev.slug === slugify(prev.title)) ? slugify(newTitle) : prev.slug
    }));
  };

  const handleCoverUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    setError('');
    try {
      const resizedBase64 = await resizeImage(file, 1200, 630);
      const blob = dataURLtoBlob(resizedBase64);
      const fileName = `blog-${Date.now()}-${file.name.replace(/[^a-zA-Z0-9.]/g, '_')}`;
      const publicUrl = await uploadImage('blog-images', fileName, blob);
      setFormData({ ...formData, cover_image: publicUrl });
    } catch (err: any) {
      setError(`Upload failed: ${err.message}.`);
    } finally {
      setIsUploading(false);
    }
  };

  const handleCreateCategory = async () => {
    const name = newCategoryName.trim();
    if (!name) return;

    try {
      const newCat = await addCategory(name);
      setFormData({ ...formData, category: newCat.name });
      setNewCategoryName('');
      setIsAddingCategory(false);
    } catch (err: any) {
      setError(`Failed to create category: ${err.message}`);
    }
  };

  const handleSave = async (e: React.FormEvent, statusOverride?: 'Published' | 'Draft') => {
    e.preventDefault();
    if (!formData.title.trim()) {
      setError("Article title is required.");
      return;
    }

    setIsSubmitting(true);
    setError('');

    const submissionData = { 
      ...formData, 
      status: statusOverride || formData.status,
      slug: formData.slug || slugify(formData.title)
    };

    try {
      if (isEditing) await updatePost(submissionData);
      else await addPost(submissionData);
      setIsSuccess(true);
      setTimeout(() => navigate('/admin/blog'), 1200);
    } catch (err: any) {
      setError(err.message || "Failed to save post.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isLoading || (isEditing && !dataLoaded)) {
    return (
      <AdminLayout>
        <div className="flex flex-col items-center justify-center min-h-[50vh]">
          <Loader2 size={32} className="animate-spin text-forge-gold mb-4" />
          <p className="font-serif italic text-slate-400">Loading Article...</p>
        </div>
      </AdminLayout>
    );
  }

  return (
    <AdminLayout>
      <div className="max-w-[1400px] mx-auto pb-20">
        <div className="flex items-center gap-4 mb-6">
          <h1 className="text-2xl font-sans font-normal text-slate-800">
            {isEditing ? 'Edit Post' : 'Add New Post'}
          </h1>
          <button type="button" onClick={() => navigate('/admin/blog/new')} className="px-2 py-1 border border-slate-300 rounded bg-white text-blue-600 text-xs font-bold hover:bg-blue-600 hover:text-white transition-colors">
            Add New
          </button>
        </div>

        {error && (
          <div className="bg-red-50 text-red-700 p-4 rounded mb-6 text-sm border border-red-200 flex items-center gap-2">
            <AlertCircle size={16} /> {error}
          </div>
        )}

        <form onSubmit={(e) => handleSave(e)} className="flex flex-col lg:flex-row gap-6">
          <div className="flex-1 space-y-4">
            <input 
              type="text" 
              value={formData.title} 
              onChange={handleTitleChange} 
              placeholder="Enter title here"
              className="w-full bg-white border border-slate-300 p-2 text-xl focus:border-blue-400 focus:outline-none"
              required
            />

            <div className="text-sm flex items-center gap-1 text-slate-600">
              <span className="font-bold">Permalink:</span>
              <span>https://theforgeproperties.com/blog/</span>
              {isEditingSlug ? (
                <div className="flex items-center gap-2">
                  <input 
                    type="text" 
                    value={formData.slug} 
                    onChange={(e) => setFormData({...formData, slug: slugify(e.target.value)})}
                    className="border border-slate-300 px-1 text-xs"
                  />
                  <button type="button" onClick={() => setIsEditingSlug(false)} className="px-2 py-0.5 bg-slate-100 border border-slate-300 text-[10px] rounded">OK</button>
                </div>
              ) : (
                <div className="flex items-center gap-2">
                  <span className="bg-yellow-50 px-1">{formData.slug || '(slug)'}</span>
                  <button type="button" onClick={() => setIsEditingSlug(true)} className="px-2 py-0.5 bg-white border border-slate-300 text-[10px] rounded hover:bg-slate-50">Edit</button>
                </div>
              )}
            </div>

            <div className="bg-white border border-slate-300">
              <RichTextEditor value={formData.content} onChange={(content) => setFormData({...formData, content})} />
            </div>

            <div className="bg-white border border-slate-300 overflow-hidden shadow-sm">
              <div className="bg-slate-50 px-3 py-2 border-b border-slate-300 flex justify-between items-center cursor-default">
